oxy_webhelp_navlinks = {"tocId-d26997e38077":{"topics":[{"title":"Add <span class=\"ph\">NAS CD<\/span> systems","shortdesc":"<p class=\"shortdesc\">You can protect unstructured data in a data storage system by adding the system in             <span class=\"ph\">NAS CD<\/span> using the <span class=\"ph\">RSC<\/span> user interface. When you add a system         using <span class=\"ph\">RSC<\/span>, you can manage protection of the <span class=\"ph\">NAS CD<\/span> data sets         by backing up, archiving or restoring the data sets using <span class=\"ph\">RSC<\/span>.<\/p>","href":"rncd\/rncd_add_systems.html","attributes":{"data-id":"rncd_add_systems"},"menu":{"hasChildren":false},"tocID":"rncd_add_systems-d26997e38078","next":"rncd_add_systems-d26997e38078"}]}};